package com.trademaster.ims.mobile.help.service;
import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.help.dto.HelpDtos.FaqResponse;import com.trademaster.ims.mobile.help.model.HelpFaq;import com.trademaster.ims.mobile.help.repository.HelpFaqRepository;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.util.StringUtils;import java.util.*;
@Service @Transactional public class HelpFaqService{private final HelpFaqRepository faqs;public HelpFaqService(HelpFaqRepository f){faqs=f;}@Transactional(readOnly=true)public List<FaqResponse>list(String category,String q){seed();List<HelpFaq>rows=StringUtils.hasText(category)?faqs.findByActiveTrueAndCategoryIgnoreCaseOrderByDisplayOrderAscQuestionAsc(category.trim()):faqs.findByActiveTrueOrderByCategoryAscDisplayOrderAscQuestionAsc();String search=q==null?null:q.trim().toLowerCase(Locale.ROOT);return rows.stream().filter(f->!StringUtils.hasText(search)||f.getQuestion().toLowerCase(Locale.ROOT).contains(search)||f.getAnswer().toLowerCase(Locale.ROOT).contains(search)).map(this::dto).toList();}@Transactional(readOnly=true)public FaqResponse get(String code){seed();return dto(faqs.findByFaqCodeAndActiveTrue(code).orElseThrow(()->new CustomerAuthException(HttpStatus.NOT_FOUND,"FAQ_NOT_FOUND","FAQ article was not found.")));}
private void seed(){add("ORDERS_TRACKING","Orders","How do I track my order?","Open My Orders, select an order, and check Delivery tracking. Tracking details appear when fulfillment updates are available.",10);add("PAYMENTS_SAFE","Payments","Which payment details are safe to enter?","Use only the checkout fields shown in the app. TechSmart Shop will never ask for your password, OTP, or card PIN in support messages.",20);add("RETURNS","Returns","Can I return a delivered item?","Delivered orders show return options when the return window is active. Return requests are reviewed before refund or replacement actions.",30);add("REVIEWS","Reviews","When can I review a product?","You can review products from delivered orders you purchased. Each delivered order item can be reviewed once.",40);add("SUPPORT","Support","How do support tickets work?","Create a ticket from Help & Support, optionally link an order, and reply from the ticket detail screen until it is closed.",50);}private void add(String c,String cat,String q,String a,int o){if(faqs.existsByFaqCode(c))return;HelpFaq f=new HelpFaq();f.setFaqCode(c);f.setCategory(cat);f.setQuestion(q);f.setAnswer(a);f.setDisplayOrder(o);faqs.save(f);}private FaqResponse dto(HelpFaq f){return new FaqResponse(f.getFaqCode(),f.getCategory(),f.getQuestion(),f.getAnswer(),f.getDisplayOrder());}}